const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');
const crypto = require('crypto');

const ALLOWED_ORIGINS = process.env.ALLOWED_ORIGINS ? process.env.ALLOWED_ORIGINS.split(',') : [];
const MAX_MESSAGE_LENGTH = 1600;
const MAX_EMAIL_BODY_LENGTH = 50000;
const RATE_LIMIT_WINDOW = 60000;
const MAX_REQUESTS_PER_WINDOW = 10;

const requestCounts = new Map();

function validateEmail(email) {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

function validatePhoneNumber(phone) {
  const phoneRegex = /^\+[1-9]\d{1,14}$/;
  return phoneRegex.test(phone);
}

function sanitizeInput(input) {
  if (typeof input !== 'string') return '';
  return input.replace(/[<>]/g, '').trim();
}

function checkRateLimit(identifier) {
  const now = Date.now();
  const userRequests = requestCounts.get(identifier) || [];
  
  const recentRequests = userRequests.filter(timestamp => now - timestamp < RATE_LIMIT_WINDOW);
  
  if (recentRequests.length >= MAX_REQUESTS_PER_WINDOW) {
    return false;
  }
  
  recentRequests.push(now);
  requestCounts.set(identifier, recentRequests);
  
  return true;
}

function validateHMAC(payload, signature, secret) {
  if (!signature || !secret) return false;
  
  const hmac = crypto.createHmac('sha256', secret);
  hmac.update(JSON.stringify(payload));
  const calculatedSignature = hmac.digest('hex');
  
  return crypto.timingSafeEqual(
    Buffer.from(signature),
    Buffer.from(calculatedSignature)
  );
}

function setCORSHeaders(res, origin) {
  if (ALLOWED_ORIGINS.length > 0 && ALLOWED_ORIGINS.includes(origin)) {
    res.set('Access-Control-Allow-Origin', origin);
  }
  res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
  res.set('Access-Control-Allow-Headers', 'Content-Type, X-Signature');
  res.set('Access-Control-Max-Age', '3600');
}

async function sendEmail(emailData, sendgridApiKey) {
  sgMail.setApiKey(sendgridApiKey);
  
  const { to, from, subject, text, html } = emailData;
  
  if (!validateEmail(to) || !validateEmail(from)) {
    throw new Error('Invalid email address');
  }
  
  if (!subject || !text) {
    throw new Error('Subject and text are required');
  }
  
  if (text.length > MAX_EMAIL_BODY_LENGTH || (html && html.length > MAX_EMAIL_BODY_LENGTH)) {
    throw new Error('Email body exceeds maximum length');
  }
  
  const msg = {
    to: sanitizeInput(to),
    from: sanitizeInput(from),
    subject: sanitizeInput(subject),
    text: sanitizeInput(text),
  };
  
  if (html) {
    msg.html = html;
  }
  
  const response = await sgMail.send(msg);
  return response;
}

async function sendSMS(smsData, twilioAccountSid, twilioAuthToken) {
  const client = twilio(twilioAccountSid, twilioAuthToken);
  
  const { to, from, body } = smsData;
  
  if (!validatePhoneNumber(to) || !validatePhoneNumber(from)) {
    throw new Error('Invalid phone number format. Use E.164 format (e.g., +1234567890)');
  }
  
  if (!body || body.length === 0) {
    throw new Error('Message body is required');
  }
  
  if (body.length > MAX_MESSAGE_LENGTH) {
    throw new Error('Message exceeds maximum length');
  }
  
  const message = await client.messages.create({
    body: sanitizeInput(body),
    from: from,
    to: to
  });
  
  return message;
}

exports.sendNotification = async (req, res) => {
  const origin = req.get('origin');
  setCORSHeaders(res, origin);
  
  if (req.method === 'OPTIONS') {
    res.status(204).send('');
    return;
  }
  
  if (req.method !== 'POST') {
    res.status(405).json({ error: 'Method not allowed' });
    return;
  }
  
  try {
    const sendgridApiKey = process.env.SENDGRID_API_KEY;
    const twilioAccountSid = process.env.TWILIO_ACCOUNT_SID;
    const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN;
    const hmacSecret = process.env.HMAC_SECRET;
    
    if (!sendgridApiKey || !twilioAccountSid || !twilioAuthToken) {
      console.error('Missing required credentials');
      res.status(500).json({ error: 'Service configuration error' });
      return;
    }
    
    const signature = req.get('X-Signature');
    if (hmacSecret && !validateHMAC(req.body, signature, hmacSecret)) {
      res.status(401).json({ error: 'Invalid signature' });
      return;
    }
    
    const clientIdentifier = req.ip || 'unknown';
    if (!checkRateLimit(clientIdentifier)) {
      res.status(429).json({ error: 'Rate limit exceeded' });
      return;
    }
    
    const { type, emailData, smsData } = req.body;
    
    if (!type || (type !== 'email' && type !== 'sms' && type !== 'both')) {
      res.status(400).json({ error: 'Invalid notification type' });
      return;
    }
    
    const results = {};
    
    if (type === 'email' || type === 'both') {
      if (!emailData) {
        res.status(400).json({ error: 'Email data is required' });
        return;
      }
      
      try {
        const emailResponse = await sendEmail(emailData, sendgridApiKey);
        results.email = {
          success: true,
          messageId: emailResponse[0].headers['x-message-id']
        };
      } catch (error) {
        results.email = {
          success: false,
          error: error.message
        };
        
        if (type === 'email') {
          res.status(500).json({ error: 'Failed to send email', details: error.message });
          return;
        }
      }
    }
    
    if (type === 'sms' || type === 'both') {
      if (!smsData) {
        res.status(400).json({ error: 'SMS data is required' });
        return;
      }
      
      try {
        const smsResponse = await sendSMS(smsData, twilioAccountSid, twilioAuthToken);
        results.sms = {
          success: true,
          messageSid: smsResponse.sid,
          status: smsResponse.status
        };
      } catch (error) {
        results.sms = {
          success: false,
          error: error.message
        };
        
        if (type === 'sms') {
          res.status(500).json({ error: 'Failed to send SMS', details: error.message });
          return;
        }
      }
    }
    
    const allSuccessful = Object.values(results).every(r => r.success);
    const statusCode = allSuccessful ? 200 : 207;
    
    res.status(statusCode).json({
      message: 'Notification processing complete',
      results: results
    });
    
  } catch (error) {
    console.error('Error processing notification:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
};